import jsPDF from 'jspdf';
import * as XLSX from 'xlsx';
import Select from 'react-select';
import { useSelector } from 'react-redux';
import { useForm } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import DataTable from 'react-data-table-component';
import React, { Fragment, useState, useEffect } from 'react';
import { Card, CardHeader, CardBody, Row, Col, Form, Dropdown, DropdownToggle, DropdownMenu, DropdownItem, TabContent, TabPane, Nav, NavItem, NavLink } from 'reactstrap';

import { messageType, } from './DropDownOption';
import { getCustomers, getCustomersRole, getSmsLogs, getWhatsAppLogs, messageLogs, } from '../../CommonUrl';
import { getClientUrlDataToken, getMasterDataToken } from '../../Utils/restUtils';
import { H3, Breadcrumbs, Btn } from '../../AbstractElements';
import { messageLogsColoumn } from './Header/ReportTableHeader';
import DatePicker from 'react-datepicker';
import HandleApiError from '../Common/ErrorImport/ErrorImport';
import Transparentspinner from '../Common/Loader/Transparentspinner';
import { Filter, Search, Export, messageLog, messageLogReport, whatsAppLogList, whatsAppLogListReport } from '../../Constant';
import moment from 'moment';
import Typeahead from '../../CommonElements/TypeAhead';

const WhatsAppLogoReport = () => {
    const { register, handleSubmit, control, formState: { errors } } = useForm({});
    const authState = useSelector((state) => state.auth);
    const searchParams = location.search;
    const params = new URLSearchParams(searchParams);

    const [messageLogData, setMessageLog] = useState([])
    const [messageLogDataSms, setMessageLogSms] = useState([])
    const [loading, setLoading] = useState(false);
    const [PrimarycolorLineTab, setPrimarycolorLineTab] = useState('1');

    const [totalRows, setTotalRows] = useState(0);
    const [perPage, setPerPage] = useState(10);
    const [currentPage, setCurrentPage] = useState(1);
    const [totalRows2, setTotalRows2] = useState(0);
    const [perPage2, setPerPage2] = useState(10);
    const [currentPage2, setCurrentPage2] = useState(1);
    const [customerSelected, setCustomerSelected] = useState()
    const [apiCustomer, setapiCustomer] = useState();
    const [dropdownOpen, setDropdownOpen] = useState(false);
    const [filters, setFilters] = useState({
        year: params.get('year') || new Date().getFullYear(),
        headerId: params.get('headerId') || '',
        type: params.get('type') || '',
        category: params.get('category') || '',
        customer_id: params.get('customer_id') || '',
        customer_name: params.get('customer_name') || '',
        search: params?.get('search') || '',
        start_date: params.get('start_date') ? moment(params.get('start_date'), "DD-MM-YYYY").toDate() : '',
        end_date: params.get('end_date') ? moment(params.get('end_date'), "DD-MM-YYYY").toDate() : '',
    })

    const [dateRange, setDateRange] = useState([filters.start_date, filters.end_date]);
    const [startDate, endDate] = dateRange
    const formatStartDate = filters.start_date ? moment(filters.start_date).format("DD-MM-YYYY") : '';
    const formatEndDate = filters.end_date ? moment(filters.end_date).format("DD-MM-YYYY") : '';
    const navigate = useNavigate();

    const toggleDropdown = () => setDropdownOpen(!dropdownOpen);
    const toggleStyle = { padding: '10px 20px', opacity: '0.8', fontSize: '14px' }

    //handle get messsage log details
    const handleGetLogDetails = async (page, size = perPage,) => {
        setLoading(true)
        let data = await getClientUrlDataToken(authState.apiUrl, getWhatsAppLogs + `?page=${page}&page_length=${size}&user_id=${authState?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sent_status=${filters?.type}&customer_id=${filters?.customer_id}&search=${filters?.search}`);
        if (data.status === true) {
            const SerialNo = (page - 1) * size + 1;

            setMessageLog(data.data.data.map((e, index) => {
                return {
                    Si: SerialNo + index,
                    messageRef: e?.ref_message_id,
                    created: e.created_date,
                    messageType: e.message_type,
                    amount: `₹ ${e.amount}`,
                    name: e.name,
                    stbId: e.subscriber_id,
                    mobile: e.mobile,
                    content: e.content,
                    type: e.type,
                    status: e.sent_status
                }
            }))
            setTotalRows2(data.data.total);
            setLoading(false)


        } else if (data.status >= 400 && data.status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (data.status >= 500 && data.status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        }
        else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
        setLoading(false)


    }
    const handleCustomerChange = (selectedOption) => {
        setCustomerSelected(selectedOption);
    };


    useEffect(() => {
        handleGetLogDetails(1);
        customerData()
        if (filters?.customer_name) {
            setCustomerSelected({ label: filters?.customer_name, value: filters?.customer_id })
        }
    }, []);

    const handlePageChange2 = page => {
        handleGetLogDetails(page);
        setCurrentPage2(page);
    }

    const handlePerRowsChange2 = async (newPerPage, page) => {
        handleGetLogDetails(page, newPerPage);
        setPerPage2(newPerPage);
    };

    const handleOnchangeType = (e) => {
        setFilters({ ...filters, type: e.target.value, category: '', headerId: '' })
    }

    const customerData = async () => {
        const data = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getCustomers : getCustomersRole);
        if (data.status === true) {
            const users = data?.data?.map((item) => (
                {
                    value: item.id,
                    label: item.name,
                }
            ))
            setapiCustomer(users);
        } else {
            HandleApiError(navigate, response.status)
        }
    };


    const onSubmit = (data) => {
        const year = filters?.year || '';
        const headerId = filters?.headerId || '';
        const category = filters?.type === '' ? '' : filters?.category || '';
        const type = filters?.type || '';
        const search = filters?.search || '';
        const customer_id = customerSelected?.value || '';
        const customer_name = customerSelected?.label || ''
        const start_date = startDate ? moment(startDate).format("DD-MM-YYYY") : '';
        const end_date = endDate ? moment(endDate).format("DD-MM-YYYY") : '';

        setFilters({
            year,
            headerId,
            category,
            type,
            search,
            start_date,
            end_date,
            customer_name,
            customer_id
        });


        const queryParams = new URLSearchParams({
            year: year,
            headerId: headerId,
            category: category,
            type: type,
            search: search,
            start_date,
            end_date,
            customer_name,
            customer_id
        }).toString();

        navigate(`/report/whatsApp-message-logs?${queryParams}`);
    }


    const exportDueExcel = async () => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, getWhatsAppLogs +
            `?export=sms-logs&user_id=${authState?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sent_status=${filters?.type}&customer_id=${filters?.customer_id}&search=${filters?.search}`);
        const dataToExport = response.data.map(({ created_date, sent_status, type, content, name, mobile, subscriber_id }) => ({ Subcriber_ID: subscriber_id, Name: name, Mobile: mobile, Status: sent_status, Type: type, Created_date: created_date, }));
        if (response.status === true) {
            const ws = XLSX.utils.json_to_sheet(dataToExport);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, 'WhatsApp Log Report');
            XLSX.writeFile(wb, 'WhatsApp_logs_data.xlsx');
        } else {
            HandleApiError(navigate, response.status);
        }
        setLoading(false);
    };

    const exportDuePdf = async () => {
        setLoading(true);
        const response = await getClientUrlDataToken(authState.apiUrl, getWhatsAppLogs +
            `?export=collection_due_data&user_id=${authState?.userId}&start_date=${formatStartDate}&end_date=${formatEndDate}&sent_status=${filters?.type}&customer_id=${filters?.customer_id}&search=${filters?.search}`);
        const dataToExport = response?.data?.map(({ created_date, sent_status, type, content, name, mobile, subscriber_id }, index) => ({ Sl: index + 1, created_date, sent_status, type, content, name, mobile, subscriber_id }));
        if (response.status === true) {
            const doc = new jsPDF();
            const columns = ["Sl", "Subscriber ID", "Name", "Mobile", "Type", "Status", "Create Date"];
            const rows = dataToExport.map(({ subscriber_id, name, mobile, type,  sent_status, created_date }, index) => [index + 1, subscriber_id, name, mobile, type, sent_status, created_date]);
            doc.autoTable({
                head: [columns],
                body: rows,
                margin: { top: 12, left: 8, right: 8, bottom: 12 },
                columnStyles: {
                    0: { cellWidth: 11 },
                    1: { cellWidth: 25 },
                    3: { cellWidth: 25 },
                    4: { cellWidth: 32 },
                    5: { cellWidth: 40 },
                },
                styles: { fontSize: 10 },
                headStyles: { fillColor: [100, 150, 200] },
            });
            doc.save("whatsApp-log-report.pdf");
        } else {
            HandleApiError(navigate, response.status);
        }
        setLoading(false);
    };



    return (
        <Fragment>
            {
                loading && <Transparentspinner />
            }
            <Breadcrumbs mainTitle={whatsAppLogList} parent="Reports" title={whatsAppLogList} />
            <Card>
                <CardHeader style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <H3>{whatsAppLogListReport}</H3>
                    </div>
                    <Dropdown isOpen={dropdownOpen} toggle={toggleDropdown}>
                        <DropdownToggle color="#fff" style={{ fontSize: '14px', zIndex: 1000 }} className="btn btn-primary mr-4">
                            {Export} <i className="icofont icofont-arrow-up"></i>
                        </DropdownToggle>
                        <DropdownMenu container="body">
                            <DropdownItem style={toggleStyle} onClick={exportDueExcel}  ><i className="fa fa-file-excel-o me-2"></i> Excel</DropdownItem>
                            <DropdownItem style={toggleStyle} onClick={exportDuePdf}  ><i className="fa fa-file-pdf-o me-2"></i> Pdf</DropdownItem>
                        </DropdownMenu>
                    </Dropdown>
                </CardHeader>
                <Form className="needs-validation" noValidate onSubmit={handleSubmit(onSubmit)}>
                    <Row className='ps-3 gap-sm-3 gap-md-2 filterGap'>
                        <Col sm="12" md="2" className="form-element">
                            <input value={filters?.search} onChange={(e) => { setFilters({ ...filters, search: e.target.value }) }} className="form-control" placeholder={Search} type="text"
                            />
                        </Col>
                        {/* <Col sm="12" md="2" className="form-element">
                            <select className="form-select" value={filters?.year} onChange={(e) => { setFilters({ ...filters, year: e.target.value }) }}  >
                                {getYearOption().map((values, index) => (
                                    <option key={values} value={values}>{values}</option>
                                ))}
                            </select>
                        </Col> */}
                        <Col sm="12" md="2" className="form-element">
                            <select className="form-select" value={filters?.type} onChange={(e) => { handleOnchangeType(e) }}  >
                                <option value='' key='type'>Status</option>
                                {messageType.map((values, index) => (
                                    <option key={values.value} value={values.value}>{values.label}</option>
                                ))}
                            </select>
                        </Col>
                        <Col sm="12" md="2" className="form-element">
                            <Select
                                isClearable
                                value={customerSelected}
                                onChange={handleCustomerChange}
                                options={apiCustomer}
                                placeholder="Customer"
                                styles={{
                                    control: (baseStyles, state) => ({
                                        ...baseStyles,
                                        height: 45,
                                    }),
                                    menu: (baseStyles) => ({
                                        ...baseStyles,
                                        zIndex: 1000,
                                    }),
                                }}
                                theme={(theme) => ({
                                    ...theme,
                                    colors: {
                                        ...theme.colors,
                                        primary25: 'rgba(83, 70, 134, 0.474)',
                                        primary: '#534686',
                                        primary50: 'rgba(83, 70, 134, 0.3)'
                                    },
                                })} />
                        </Col>
                        <Col sm="12" md="5" lg='3' className="form-element" >
                            <div style={{ position: 'relative', zIndex: 2 }}>
                                <DatePicker
                                    className="form-control digits w-100"
                                    selectsRange={true}
                                    startDate={startDate}
                                    endDate={endDate}
                                    onChange={(update) => {
                                        setDateRange(update);
                                    }}
                                    dateFormat="dd-MM-yyyy"
                                    isClearable={startDate ? true : false}
                                    monthsShown={2}
                                    popperPlacement="bottom"
                                    calendarClassName='parallel-calendar'
                                    placeholderText='Select Date Range'
                                />
                            </div>
                        </Col>


                        <Col sm="12" md="2" className="custom-filtrs">
                            <Btn attrBtn={{ color: "primary" }} type="submit">{Filter}</Btn>
                        </Col>
                    </Row>
                </Form>

                <CardBody>
                    <div className="order-history table-responsive">
                        <DataTable
                            columns={messageLogsColoumn()}
                            data={messageLogData}
                            pagination
                            paginationServer
                            defaultSortAsc
                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                            paginationTotalRows={totalRows2}
                            paginationDefaultPage={currentPage2}
                            onChangeRowsPerPage={handlePerRowsChange2}
                            onChangePage={handlePageChange2}
                            fixedHeader
                        />

                    </div>
                </CardBody>
            </Card>
        </Fragment>
    );
};

export default WhatsAppLogoReport;